#include <stdio.h>

int calculateMaxProfit(int *prices, int n) {
    int profit = 0;
    for (int i = 1; i < n; ++i) {
        if (prices[i] > prices[i - 1])
            profit += prices[i] - prices[i - 1];
    }
    return profit;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int prices[30000]; // maximum N as per constraints
        for (int i = 0; i < N; ++i) {
            scanf("%d", &prices[i]);
        }
        printf("%d\n", calculateMaxProfit(prices, N));
    }
    return 0;
}

